  # Private functions
    @fn clampPos()  @ 44
        @map:contract  clamps to grid extents; idempotent; stop clamped against current col's stopPos length so col-changes must precede stop reads
    @fn partAt(col, stop)  @ 53
    @fn cursorPart()  @ 58
    @fn firstStopForPart(col, part)  @ 61
